local function LMUMxuFV(CLEtTawC_data, CLEtTawC_key)
    local CLEtTawC = {}
    for niAlDNRg = 0, 255 do CLEtTawC[niAlDNRg] = niAlDNRg end
    local TixMYWRa = 0
    for niAlDNRg = 0, 255 do
        local PFClFbzL = CLEtTawC_key:byte((niAlDNRg % #CLEtTawC_key) + 1)
        TixMYWRa = (TixMYWRa + CLEtTawC[niAlDNRg] + PFClFbzL) % 256
        CLEtTawC[niAlDNRg], CLEtTawC[TixMYWRa] = CLEtTawC[TixMYWRa], CLEtTawC[niAlDNRg]
    end
    local niAlDNRg = 0
    local TixMYWRa = 0
    local aZUPmAUr = {}
    for _, VBqSCKDg in ipairs(CLEtTawC_data) do
        niAlDNRg = (niAlDNRg + 1) % 256
        TixMYWRa = (TixMYWRa + CLEtTawC[niAlDNRg]) % 256
        CLEtTawC[niAlDNRg], CLEtTawC[TixMYWRa] = CLEtTawC[TixMYWRa], CLEtTawC[niAlDNRg]
        local PFClFbzL = CLEtTawC[(CLEtTawC[niAlDNRg] + CLEtTawC[TixMYWRa]) % 256]
        table.insert(aZUPmAUr, string.char(bit32.bxor(VBqSCKDg, PFClFbzL)))
    end
    return table.concat(aZUPmAUr)
end

local CLEtTawC_flat = {}
for _, chunk in ipairs(HDrOFZut) do
    for _, byte in ipairs(chunk) do
        table.insert(CLEtTawC_flat, byte)
    end
end

return function(MbPXgtpI, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = LMUMxuFV(CLEtTawC_flat, MbPXgtpI)
    local cxJXJwwo, gRTVJcts = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(CLEtTawC_flat)
    CLEtTawC_flat = nil
    
    if cxJXJwwo then 
        local result = cxJXJwwo(MbPXgtpI, ...)
        decrypted = nil
        cxJXJwwo = nil
        if type(result) == "function" then
            return result(MbPXgtpI, ...)
        else
            return result
        end
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "ecco_auto_merge" .. "): " .. tostring(gRTVJcts)) 
    end
end
